3	const areSameCell = (a: Cell, b: Cell): boolean => a[0] === b[0] && a[1] === b[1];
4	
5	const areNeighbors = (a: Cell, b: Cell): boolean =>
6	  !areSameCell(a, b) && Math.abs(a[0] - b[0]) <= 1 && Math.abs(a[1] - b[1]) <= 1;
7	
8	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
9	  liveCells.filter((other) => areNeighbors(cell, other)).length;
